# Python 3.11+
"""Domain model for a two-player Chess engine.

The teaching point of this problem is PURE object-oriented domain modeling, so
the cleverness lives here, not in a concurrency layer. The one idea that shapes
everything: each Piece subclass knows how to generate its OWN candidate moves
(`candidate_moves`). The Board and the ChessGame never switch on piece kind —
adding a new piece is a new subclass and ZERO engine edits.

🎙️ "I push the per-piece movement rules INTO the pieces. The board is a dumb
8x8 grid, the game owns the turn and the one cross-cutting rule (you may not
leave your own king in check). Everything piece-specific is polymorphic."
"""

from abc import ABC, abstractmethod
from dataclasses import dataclass
from enum import Enum


# ── VOCABULARY (enums = shared vocabulary, not entities) ─────────────────────
class Color(Enum):
    WHITE = "WHITE"
    BLACK = "BLACK"

    def opponent(self) -> "Color":
        # WHY: turn alternation and "is the enemy attacking my king?" both need
        #      the other side; one place to flip it keeps callers honest.
        return Color.BLACK if self is Color.WHITE else Color.WHITE


class PieceType(Enum):
    KING = "K"
    QUEEN = "Q"
    ROOK = "R"
    BISHOP = "B"
    KNIGHT = "N"
    PAWN = "P"


class GameStatus(Enum):
    ONGOING = "ONGOING"        # side to move has at least one legal move, not in check
    CHECK = "CHECK"            # side to move is in check but can escape
    CHECKMATE = "CHECKMATE"    # side to move is in check with no legal move — game over
    STALEMATE = "STALEMATE"    # side to move is NOT in check but has no legal move — draw


# ── EXCEPTIONS (one base, one subclass per failure mode) ─────────────────────
class ChessError(Exception):
    """Base for every error this engine raises — callers catch one type."""


class InvalidPositionError(ChessError):
    """A square is off the 8x8 board, or a required king is missing."""


class IllegalMoveError(ChessError):
    """The move breaks a rule: not a candidate, captures own piece, or leaves
    the mover's own king in check."""


class WrongTurnError(ChessError):
    """A player tried to move a piece that is not their color."""


class GameOverError(ChessError):
    """A move was attempted after CHECKMATE or STALEMATE."""


# ── VALUE OBJECT: Position / Square (frozen — a coordinate never mutates) ─────
@dataclass(frozen=True)
class Position:
    # ── WHY THIS CLASS ────────────────────────────────────────────────────────
    # A board coordinate as (file, rank), each 0..7. file = column a-h, rank =
    # row 1-8. Frozen because a square is a pure value — two squares with the
    # same file/rank ARE the same square, so it doubles as a dict/set key.
    file: int   # column, 0 = 'a' .. 7 = 'h'
    rank: int   # row,    0 = '1' .. 7 = '8'

    @staticmethod
    def on_board(file: int, rank: int) -> bool:
        # WHY: move generators compute raw offsets that may fall off the edge;
        #      they check this BEFORE building a Position so an off-board square
        #      is never even represented.
        return 0 <= file < 8 and 0 <= rank < 8

    def is_on_board(self) -> bool:
        return Position.on_board(self.file, self.rank)

    def __str__(self) -> str:
        if not self.is_on_board():
            return f"({self.file},{self.rank})"
        return f"{'abcdefgh'[self.file]}{self.rank + 1}"


# `Square` is an alias — some people say "square", some say "position". Same value.
Square = Position


# ── VALUE OBJECT: Move (frozen — a played move is history, it never changes) ──
@dataclass(frozen=True)
class Move:
    # ── WHY THIS CLASS ────────────────────────────────────────────────────────
    # One played (or candidate) move: from-square, to-square, plus two facts the
    # engine resolved at apply time — what the pawn promoted to, and whether it
    # was a capture. Frozen so the move history is a tamper-proof record.
    frm: Position
    to: Position
    promotion: PieceType | None = None
    is_capture: bool = False

    def __str__(self) -> str:
        tag = "x" if self.is_capture else "-"
        promo = f"={self.promotion.value}" if self.promotion else ""
        return f"{self.frm}{tag}{self.to}{promo}"


# ── PIECE: abstract base with the polymorphic move generator ─────────────────
class Piece(ABC):
    # ── WHY THIS CLASS ────────────────────────────────────────────────────────
    # The abstraction the whole engine leans on. Every concrete piece answers ONE
    # question: "from this square, on this board, where could I move?" The base
    # provides two shared walkers — a ray walk (for sliding pieces) and a single
    # step walk (for King/Knight) — so subclasses stay tiny.
    #
    # NOTE: candidate_moves returns PSEUDO-LEGAL targets — it honors movement
    # shape, the board edges, blockers, and "don't land on your own piece", but
    # it does NOT know about check. The one cross-cutting "don't expose your
    # king" rule is enforced ONCE in ChessGame, never duplicated per piece.
    def __init__(self, color: Color) -> None:
        self.color = color

    @property
    @abstractmethod
    def piece_type(self) -> PieceType:
        raise NotImplementedError

    @abstractmethod
    def candidate_moves(self, board: "Board", pos: "Position") -> list[Position]:
        raise NotImplementedError

    # ── shared helper: ray walk for sliding pieces (Queen/Rook/Bishop) ──
    def _ray_moves(self, board: "Board", pos: Position,
                   directions: list[tuple[int, int]]) -> list[Position]:
        moves: list[Position] = []
        for df, dr in directions:
            step = 1

            while True:
                nf, nr = pos.file + df * step, pos.rank + dr * step
                if not Position.on_board(nf, nr):
                    break
                target = Position(nf, nr)
                occupant = board.get(target)
                if occupant is None:
                    moves.append(target)               # empty — keep sliding
                elif occupant.color != self.color:
                    moves.append(target)               # enemy — capture, then stop
                    break
                else:
                    break                              # own piece — blocked, stop
                step += 1
        return moves

    # ── shared helper: single-step walk for King/Knight ──
    def _step_moves(self, board: "Board", pos: Position,
                    deltas: list[tuple[int, int]]) -> list[Position]:
        moves: list[Position] = []
        for df, dr in deltas:
            nf, nr = pos.file + df, pos.rank + dr
            if not Position.on_board(nf, nr):
                continue
            target = Position(nf, nr)
            occupant = board.get(target)
            if occupant is None or occupant.color != self.color:
                moves.append(target)                   # empty or enemy — legal target
        return moves

    @property
    def symbol(self) -> str:
        # Uppercase for white, lowercase for black — standard board notation.
        letter = self.piece_type.value
        return letter if self.color is Color.WHITE else letter.lower()

    def __repr__(self) -> str:
        return f"{self.color.name[0]}{self.piece_type.value}"


_ORTHOGONAL = [(1, 0), (-1, 0), (0, 1), (0, -1)]
_DIAGONAL = [(1, 1), (1, -1), (-1, 1), (-1, -1)]
_KNIGHT_DELTAS = [(1, 2), (2, 1), (2, -1), (1, -2),
                  (-1, -2), (-2, -1), (-2, 1), (-1, 2)]


class King(Piece):
    @property
    def piece_type(self) -> PieceType:
        return PieceType.KING

    def candidate_moves(self, board: "Board", pos: Position) -> list[Position]:
        # One step in any of the 8 directions. (Castling is a documented twist.)
        return self._step_moves(board, pos, _ORTHOGONAL + _DIAGONAL)


class Queen(Piece):
    @property
    def piece_type(self) -> PieceType:
        return PieceType.QUEEN

    def candidate_moves(self, board: "Board", pos: Position) -> list[Position]:
        # Rook + Bishop — slides along all 8 lines.
        return self._ray_moves(board, pos, _ORTHOGONAL + _DIAGONAL)


class Rook(Piece):
    @property
    def piece_type(self) -> PieceType:
        return PieceType.ROOK

    def candidate_moves(self, board: "Board", pos: Position) -> list[Position]:
        return self._ray_moves(board, pos, _ORTHOGONAL)


class Bishop(Piece):
    @property
    def piece_type(self) -> PieceType:
        return PieceType.BISHOP

    def candidate_moves(self, board: "Board", pos: Position) -> list[Position]:
        return self._ray_moves(board, pos, _DIAGONAL)


class Knight(Piece):
    @property
    def piece_type(self) -> PieceType:
        return PieceType.KNIGHT

    def candidate_moves(self, board: "Board", pos: Position) -> list[Position]:
        # The only piece that jumps — blockers do not matter, so a step walk fits.
        return self._step_moves(board, pos, _KNIGHT_DELTAS)


class Pawn(Piece):
    @property
    def piece_type(self) -> PieceType:
        return PieceType.PAWN

    def candidate_moves(self, board: "Board", pos: Position) -> list[Position]:
        # WHY: a pawn is the one asymmetric piece — direction depends on color,
        #      it pushes straight but captures diagonally, and it gets a 2-square
        #      first move. All of that is local to this one class.
        moves: list[Position] = []
        direction = 1 if self.color is Color.WHITE else -1
        start_rank = 1 if self.color is Color.WHITE else 6

        one = Position(pos.file, pos.rank + direction)
        if one.is_on_board() and board.get(one) is None:
            moves.append(one)                          # single push onto empty square
            two = Position(pos.file, pos.rank + 2 * direction)
            if pos.rank == start_rank and board.get(two) is None:
                moves.append(two)                      # double push from home rank

        for df in (-1, 1):
            diag = Position(pos.file + df, pos.rank + direction)
            if not diag.is_on_board():
                continue
            occupant = board.get(diag)
            if occupant is not None and occupant.color != self.color:
                moves.append(diag)                     # diagonal capture only if enemy
        return moves


# ── FACTORY: PieceType -> the matching Piece subclass ────────────────────────
_PIECE_CLASSES: dict[PieceType, type[Piece]] = {
    PieceType.KING: King,
    PieceType.QUEEN: Queen,
    PieceType.ROOK: Rook,
    PieceType.BISHOP: Bishop,
    PieceType.KNIGHT: Knight,
    PieceType.PAWN: Pawn,
}


def make_piece(piece_type: PieceType, color: Color) -> Piece:
    # WHY: board setup and pawn promotion both need "give me an X of this color".
    #      Centralizing the enum -> class translation means callers never import
    #      every subclass, and a new piece registers in exactly one place.
    return _PIECE_CLASSES[piece_type](color)


# ── BOARD: a dumb 8x8 grid of Optional[Piece] ────────────────────────────────
class Board:
    # ── WHY THIS CLASS ────────────────────────────────────────────────────────
    # Pure storage + geometry. It can place, fetch, relocate a piece, find a
    # king, and clone itself — but it knows NOTHING about whose turn it is or
    # whether a move is legal. That separation is what keeps the engine clean:
    # the Board answers "what is where", the pieces answer "where can I go", the
    # game answers "is this move allowed".
    def __init__(self, grid: list[list[Piece | None]] | None = None) -> None:
        self._grid: list[list[Piece | None]] = grid or [[None] * 8 for _ in range(8)]

    @classmethod
    def standard(cls) -> "Board":
        """Build the standard chess starting position."""
        board = cls()
        back_rank = [PieceType.ROOK, PieceType.KNIGHT, PieceType.BISHOP, PieceType.QUEEN,
                     PieceType.KING, PieceType.BISHOP, PieceType.KNIGHT, PieceType.ROOK]
        for file, ptype in enumerate(back_rank):
            board.set(Position(file, 0), make_piece(ptype, Color.WHITE))
            board.set(Position(file, 1), make_piece(PieceType.PAWN, Color.WHITE))
            board.set(Position(file, 6), make_piece(PieceType.PAWN, Color.BLACK))
            board.set(Position(file, 7), make_piece(ptype, Color.BLACK))
        return board

    def get(self, pos: Position) -> Piece | None:
        return self._grid[pos.rank][pos.file]

    def set(self, pos: Position, piece: Piece | None) -> None:
        self._grid[pos.rank][pos.file] = piece

    def move_piece(self, frm: Position, to: Position) -> Piece | None:
        # Relocate the piece; return whatever was captured (or None). No rule
        # checking here — the game has already validated by the time we get here.
        captured = self._grid[to.rank][to.file]
        self._grid[to.rank][to.file] = self._grid[frm.rank][frm.file]
        self._grid[frm.rank][frm.file] = None
        return captured

    def find_king(self, color: Color) -> Position:
        for rank in range(8):
            for file in range(8):
                piece = self._grid[rank][file]
                if piece is not None and piece.piece_type is PieceType.KING and piece.color is color:
                    return Position(file, rank)
        raise InvalidPositionError(f"no {color.name} king on the board")

    def pieces_of(self, color: Color) -> list[tuple[Position, Piece]]:
        found: list[tuple[Position, Piece]] = []
        for rank in range(8):
            for file in range(8):
                piece = self._grid[rank][file]
                if piece is not None and piece.color is color:
                    found.append((Position(file, rank), piece))
        return found

    def copy(self) -> "Board":
        # WHY: legality testing simulates a move on a CLONE so the real board is
        #      never half-mutated. Pieces are stateless (color/type only), so we
        #      reuse the same piece objects — only the grid of references is new.
        return Board([row[:] for row in self._grid])

# Python 3.11+
"""ChessGame — the orchestrator — plus a thread-safe subclass.

ChessGame owns the truth: the board, whose turn it is, the move history, and the
current status. Its public surface is small (`move`, `legal_moves`, `is_in_check`,
`status`, `piece_at`). The interesting design choice is what it DOESN'T do: it
never switches on piece kind (the pieces answer that polymorphically) and it
enforces the one cross-cutting rule — "you may not leave your own king in check"
— in exactly ONE place, by simulating the move on a board clone and re-checking.

Concurrency here is light by design: chess is turn-based and single-threaded.
The clean core has a no-op `_lock()` hook; `ThreadSafeChessGame` overrides it
with a single per-game lock so two threads can't both apply a move at once.
"""

import threading
from contextlib import contextmanager
from typing import Iterator

from models import (
    Board,
    ChessError,
    Color,
    GameOverError,
    GameStatus,
    IllegalMoveError,
    InvalidPositionError,
    Move,
    Piece,
    PieceType,
    Position,
    WrongTurnError,
    make_piece,
)

_PROMOTION_RANK = {Color.WHITE: 7, Color.BLACK: 0}
_VALID_PROMOTIONS = {PieceType.QUEEN, PieceType.ROOK, PieceType.BISHOP, PieceType.KNIGHT}
_TERMINAL_STATUS = {GameStatus.CHECKMATE, GameStatus.STALEMATE}


class ChessGame:
    # ── WHY THIS CLASS ────────────────────────────────────────────────────────
    # The brain. Every move flows through here so the rules are enforced in one
    # place. It coordinates the dumb Board and the smart Pieces but implements no
    # per-piece movement logic itself.
    def __init__(self, board: Board | None = None, turn: Color = Color.WHITE) -> None:
        self._board = board if board is not None else Board.standard()
        self._turn = turn
        self._history: list[Move] = []
        self._status = self._compute_status()

    # ── read-only views ──
    @property
    def current_turn(self) -> Color:
        return self._turn

    @property
    def history(self) -> list[Move]:
        return list(self._history)               # defensive copy — history is read-only

    # ── concurrency hook: does NOTHING in the clean core. ──
    @contextmanager
    def _lock(self) -> Iterator[None]:
        # WHY: this is a placeholder the thread-safe subclass replaces with a
        #      real lock. The clean engine has zero lock code, so the OO design
        #      is the star; §9 swaps in safety by overriding only this method.
        yield

    # ── public surface ──
    def piece_at(self, pos: Position) -> Piece | None:
        if not pos.is_on_board():
            raise InvalidPositionError(f"{pos} is off the board")
        return self._board.get(pos)

    def is_in_check(self, color: Color) -> bool:
        # The king is in check if any enemy piece's candidate moves hit its square.
        king = self._board.find_king(color)
        return self._is_attacked(self._board, king, color.opponent())

    def status(self) -> GameStatus:
        return self._status

    def legal_moves(self, color: Color | None = None) -> list[Move]:
        # Every pseudo-legal move that ALSO does not leave the mover's king in
        # check. This single method powers both the bot and mate/stalemate
        # detection (no legal move = the game is decided).
        side = color if color is not None else self._turn
        result: list[Move] = []
        for frm, piece in self._board.pieces_of(side):
            for to in piece.candidate_moves(self._board, frm):

                if self._leaves_king_in_check(side, frm, to):
                    continue
                promo = self._auto_promotion(piece, to)
                result.append(Move(frm, to, promo, self._board.get(to) is not None))
        return result

    def move(self, frm: Position, to: Position, promotion: PieceType | None = None) -> Move:
        # ── THE pipeline: validate -> (king-safety) -> apply -> switch -> restatus.
        with self._lock():
            if self._status in _TERMINAL_STATUS:
                raise GameOverError(f"game is over ({self._status.value}); no moves allowed")
            self._validate_squares(frm, to)
            piece = self._board.get(frm)
            if piece is None:
                raise IllegalMoveError(f"no piece on {frm}")
            if piece.color is not self._turn:
                raise WrongTurnError(f"it is {self._turn.name}'s turn, not {piece.color.name}'s")
            if to not in piece.candidate_moves(self._board, frm):
                raise IllegalMoveError(f"{piece.piece_type.name} cannot move {frm} -> {to}")
            if self._leaves_king_in_check(self._turn, frm, to):
                raise IllegalMoveError(f"move {frm} -> {to} would leave the {self._turn.name} king in check")

            applied = self._apply(frm, to, piece, promotion)
            self._turn = self._turn.opponent()
            self._status = self._compute_status()
            self._history.append(applied)
            return applied

    # ── private helpers ──
    def _validate_squares(self, frm: Position, to: Position) -> None:
        if not frm.is_on_board():
            raise InvalidPositionError(f"from-square {frm} is off the board")
        if not to.is_on_board():
            raise InvalidPositionError(f"to-square {to} is off the board")
        if frm == to:
            raise IllegalMoveError("from-square and to-square are the same")

    def _apply(self, frm: Position, to: Position, piece: Piece,
               promotion: PieceType | None) -> Move:
        # Relocate, then promote in place if a pawn reached the last rank.
        captured = self._board.move_piece(frm, to)
        promo_type: PieceType | None = None
        if piece.piece_type is PieceType.PAWN and to.rank == _PROMOTION_RANK[piece.color]:
            promo_type = promotion or PieceType.QUEEN     # basic promotion defaults to Queen
            if promo_type not in _VALID_PROMOTIONS:
                raise IllegalMoveError(f"cannot promote to {promo_type.name}")
            self._board.set(to, make_piece(promo_type, piece.color))
        return Move(frm, to, promo_type, captured is not None)

    def _auto_promotion(self, piece: Piece, to: Position) -> PieceType | None:
        # legal_moves reports promoting pawn pushes as "=Q" (the default choice).
        if piece.piece_type is PieceType.PAWN and to.rank == _PROMOTION_RANK[piece.color]:
            return PieceType.QUEEN
        return None

    def _leaves_king_in_check(self, color: Color, frm: Position, to: Position) -> bool:
        # WHY: the ONE cross-cutting rule. Simulate the move on a CLONE, then ask
        #      "is my king attacked now?" — never duplicated inside a piece.
        sim = self._board.copy()
        sim.move_piece(frm, to)
        king = sim.find_king(color)
        return self._is_attacked(sim, king, color.opponent())

    def _is_attacked(self, board: Board, square: Position, by_color: Color) -> bool:
        # True if any `by_color` piece could capture onto `square`. Reuses the
        # exact same candidate_moves the pieces expose — one source of truth for
        # "where can this piece reach" covers both moving and attacking.
        for frm, piece in board.pieces_of(by_color):
            if square in piece.candidate_moves(board, frm):
                return True
        return False

    def _compute_status(self) -> GameStatus:
        in_check = self.is_in_check(self._turn)
        has_move = len(self.legal_moves(self._turn)) > 0
        if in_check and not has_move:
            return GameStatus.CHECKMATE
        if not in_check and not has_move:
            return GameStatus.STALEMATE
        if in_check:
            return GameStatus.CHECK
        return GameStatus.ONGOING


class ThreadSafeChessGame(ChessGame):
    # ── WHY THIS CLASS ────────────────────────────────────────────────────────
    # Chess is turn-based, so concurrency is minimal. The ONLY shared-state risk
    # is two threads calling `move` at the same instant. A single per-game lock
    # serializes them: one move applies, the other re-enters after the turn has
    # already flipped and is rejected by the normal turn check. We use RLock
    # because a guarded method could call another guarded method on the same
    # thread; reentrancy keeps that from self-deadlocking.
    def __init__(self, board: Board | None = None, turn: Color = Color.WHITE) -> None:
        self._game_lock = threading.RLock()
        super().__init__(board, turn)

    @contextmanager
    def _lock(self) -> Iterator[None]:
        with self._game_lock:
            yield


__all__ = ["ChessGame", "ThreadSafeChessGame", "ChessError"]

